#!/usr/bin/env bash
# Сборка образа через compose с повтором.
#
# ЗАЧЕМ. CD собирал образ одной попыткой, в отличие от backend-ci, где повтор
# есть с 2026-07-17. Расхождение было невидимым: workflow разные, сборка одна и
# та же, и разница проявлялась только когда канал подводил.
#
# Отказ 2026-07-19 пришёл именно сюда — но по другой причине, чем таймаут:
#
#   #10 ... P=""  → «прокси не задан — Gradle пойдёт напрямую»
#   #16 Plugin [id: 'io.quarkus', version: '3.36.1'] was not found
#
# Прокси в сборку не передавался вовсе, и Gradle внутри образа оставался без
# маршрута наружу. Сообщение обманчиво: читается как отсутствующий плагин, а на
# деле нет пути до plugins.gradle.org. Это чинится передачей build-args и
# зеркалом (см. docker-compose.yml), а повтор здесь — для остатка, который
# зеркало не покрывает: дистрибутив Gradle и базовые образы.
#
# Повтор дёшев: слои кэшируются, вторая попытка переигрывает только упавший шаг.
set -uo pipefail

ATTEMPTS="${COMPOSE_BUILD_ATTEMPTS:-3}"
DELAY="${COMPOSE_BUILD_DELAY:-15}"

if [ "$#" -eq 0 ]; then
  echo "::error::compose-build-retry.sh вызван без имени сервиса"
  exit 2
fi

attempt=1
while : ; do
  echo "::group::docker compose build $* (попытка $attempt из $ATTEMPTS)"
  # Код возврата снимается в ветке else: после `fi` он был бы нулевым, потому
  # что `if` без else возвращает 0 при провалившемся условии — и скрипт
  # «падал бы успешно», маскируя ровно те отказы, ради которых написан.
  if docker compose build "$@"; then
    echo "::endgroup::"
    [ "$attempt" -gt 1 ] && echo "::notice::образ собрался с попытки $attempt — канал нестабилен"
    exit 0
  else
    rc=$?
  fi
  echo "::endgroup::"

  # ОТКАТ ОТ ЗЕРКАЛА — тем же приёмом, что в gradle-retry.sh: первая неудача
  # обнуляет адреса, и следующая сборка идёт в публичные репозитории. Пустое
  # значение Dockerfile понимает («зеркало не задано»), поэтому достаточно
  # снять переменные — build-args пересчитаются, слой с init-скриптом
  # инвалидируется и пересоберётся уже без него.
  if [ -n "${LORE_MAVEN_MIRROR:-}" ]; then
    export LORE_MAVEN_MIRROR="" LORE_PLUGIN_MIRROR=""
    echo "::warning::сборка с зеркалом Nexus не удалась — следующая попытка пойдёт напрямую"
  fi

  if [ "$attempt" -ge "$ATTEMPTS" ]; then
    echo "::error::сборка образа не удалась $ATTEMPTS раза подряд (код $rc). Столько отказов подряд на сеть не спишешь — смотрите причину в логе выше."
    exit "$rc"
  fi

  echo "::warning::попытка $attempt не удалась (код $rc), повтор через ${DELAY}с"
  sleep "$DELAY"
  attempt=$((attempt + 1))
done
